 1	import * as React from 'react';
 2	
 3	import { Button, FormGroup, GridItem } from '@patternfly/react-core';
 4	
 5	type PlainIconButtonProps = {
 6	  fieldId: string;
 7	  icon: React.ReactNode;
 8	  onClick: () => void;
 9	};
10	
11	const PlainIconButton: React.FC<PlainIconButtonProps> = ({ fieldId, icon, onClick }) => {
12	  return (
13	    <GridItem span={1}>
14	      <FormGroup fieldId={fieldId} label=" ">
15	        <Button onClick={onClick} variant="plain">
16	          {icon}
17	        </Button>
18	      </FormGroup>
19	    </GridItem>
20	  );
21	};
22	
23	export default PlainIconButton;

